        cover = "Interface\\AddOns\\AltertimeAddon\\Media\\Covers\\algunos-miembros-del-equipo-de-world-of-warcraft-ayudaron-en-la-construccion-para-las-vict_01_11b87505.tga",
        body = {
            { type = "paragraph", text = "El devastador incendio de Eaton el invierno pasado arrasó una buena parte de Los Ángeles en California, dejando a miles de personas sin hogar. Este año como parte de su campaña benéfica anual, Blizzard puso a la venta el pack de Rufus, cuyos fondos recaudados serán destinados a la organización Habitat for Humanity. Además, algunos miembros del equipo han colaborado recientemente a construir refugios como parte de la misma campaña." },
            { type = "paragraph", text = "Tanto parte del equipo de desarrollo como Holly Longdale y Joanna Faris viajaron a la zona para ayudar a los trabajadores a construir lo refugios. Os dejamos por aquí algunas de las imagenes compartidas en la cuenta oficial de Instragram de Warcraft :" },
            { type = "image", path = "Interface\\AddOns\\AltertimeAddon\\Media\\Inline\\algunos-miembros-del-equipo-de-world-of-warcraft-ayudaron-en-la-construccion-para-las-vict_02_bdd23a0d.tga", width = 760, height = 506 },
