        title = "Los Campos de Entrenamientos (JcJ) llegan a Midnight",
        excerpt = "Los jugadores nuevos en el JcJ podrán aprender sus reglas en el Campo de Entrenamiento. Aquí se amplía y renueva la idea que se encuentra en Entorno hostil, donde los jugadores se unirán a una batalla contra oponentes más inteligentes controlados por el juego ",
        author = "AlterTime",
