    {
        id = "c5a864aafb65",
        slug = "cambios-a-las-profesiones-que-llegaran-con-midnight",
        title = "Cambios a las profesiones que llegarán con Midnight",
        excerpt = "Con un renovado sistema de profesiones que llegó en Dragonflight, Blizzard ha continuado añadiendo novedades y mejorando este sistema para hacer que sea lo mas claro y sencillo posible para los jugadores sin perder toda la nueva profundidad que ofrece el siste",
        author = "AlterTime",
        publishedAt = 1778516264,
        categories = { "AlterTime" },
        url = "https://altertime.es/article/cambios-a-las-profesiones-que-llegaran-con-midnight",
        cover = "Interface\\AddOns\\AltertimeAddon\\Media\\Covers\\cambios-a-las-profesiones-que-llegaran-con-midnight_01_0f5e4695.tga",
        body = {
            { type = "paragraph", text = "Con un renovado sistema de profesiones que llegó en Dragonflight, Blizzard ha continuado añadiendo novedades y mejorando este sistema para hacer que sea lo mas claro y sencillo posible para los jugadores sin perder toda la nueva profundidad que ofrece el sistema. Con la llegada de Midnight, llegarán algunas novedades que buscan simplificar las profesiones para hacerlas mas asequibles a los jugadores que aún no han comprendido del todo bien el funcionamiento del sistema:" },
            { type = "bullet", text = "Calidad de los componentes: En Midnight, tanto los componentes (hierbas, minerales, cuero, etc…) como consumibles (pociones, frascos, comida, etc…) tendrán dos calidades distintas en lugar de las tres a las que estábamos acostumbrados. Esto simplificará el sistema y ahorrará mucho espacio en nuestras mochilas." },
            { type = "bullet", text = "Agudeza de artesano por profesión: La agudeza de artesano cambiará de nombre a Arrojo de artesano y será específica de profesión ( Arrojo de alquimista artesano , Arrojo de herrero artesano , etc…). Esto evitará la práctica de olvidar y aprender nuevas profesiones al principio de la expansión para acumular agudeza y adquirir nuevas recetas o puntos de conocimiento." },
            { type = "bullet", text = "Herramientas de profesión: Midnight traerá la tercera ronda de equipamiento de profesión, ampliando las opciones que ya tenemos disponibles. Por el momento, fabricar este equipo no requiere Arrojo de artesano ." },
            { type = "bullet", text = "Especializaciones: Los árboles de especialización han sufrido algunos ajustes y se han añadido algunas recetas. Aún así, la estructura general se mantiene sin cambios." },
            { type = "bullet", text = "Mecánicas eliminadas: Algunas mecánicas ya obsoletas han sido eliminadas, por ejemplo alquimia ha sustituido el descubrimiento de recetas de forma aleatoria por un sistema de investigación mas sencillo basado en el desbloqueo por logros. Otra modificación es la adaptación de recetas al botín de banda y a los vendedores de reputación así como la optimización de recetas complicadas." },
            { type = "paragraph", text = "12/5/2026" },
            { type = "heading", text = "Tyrande/Colinas Pardas/Los Errantes" },
            { type = "bullet", text = "Fetiche de Sen'jin" },
            { type = "bullet", text = "Celada Rompeterra" },
            { type = "image", path = "Interface\\AddOns\\AltertimeAddon\\Media\\Inline\\cambios-a-las-profesiones-que-llegaran-con-midnight_02_9bc7a79d.tga", width = 760, height = 490 },
        },
    },
