        body = {
            { type = "paragraph", text = "Con el lanzamiento completo del sistema de Housing en Midnight llegarán también los Proyectos de Vecindario, unos eventos temáticos que permitirá a los jugadores desbloquear mas decoraciones a sus hogares realizando ciertas actividades. Podeis encontrar mas información sobre los Proyectos en nuestro artículo en AlterTime ." },
            { type = "heading", text = "Ayuda artística" },
